async function handleRequest(request) {
  const url = new URL(request.url);
  
  const customTTL = url.searchParams.get('ttl');
  const customCacheKey = url.searchParams.get('cache_key');
  
  url.searchParams.delete('ttl');
  url.searchParams.delete('cache_key');
  
  const cacheKey = customCacheKey 
    ? new Request(new URL(customCacheKey, url.origin).toString(), request)
    : new Request(url.toString(), request);
  
  const cache = caches.default;
  
  let response = await cache.match(cacheKey);
  
  if (response) {
    const cacheStatus = response.headers.get('CF-Cache-Status');
    response = new Response(response.body, response);
    response.headers.set('X-Cache', 'HIT');
    response.headers.set('X-Cache-Key', cacheKey.url);
    return response;
  }
  
  response = await fetch(url.toString(), {
    method: request.method,
    headers: request.headers,
    body: request.body,
    redirect: request.redirect
  });
  
  if (response.ok && request.method === 'GET') {
    const ttl = customTTL ? parseInt(customTTL, 10) : 3600;
    
    if (ttl > 0 && ttl <= 31536000) {
      const cacheResponse = new Response(response.clone().body, response);
      
      cacheResponse.headers.set('Cache-Control', `public, max-age=${ttl}`);
      cacheResponse.headers.set('X-Cache', 'MISS');
      cacheResponse.headers.set('X-Cache-Key', cacheKey.url);
      cacheResponse.headers.set('X-Cache-TTL', ttl.toString());
      
      event.waitUntil(cache.put(cacheKey, cacheResponse));
      
      const clientResponse = new Response(response.body, response);
      clientResponse.headers.set('X-Cache', 'MISS');
      clientResponse.headers.set('X-Cache-Key', cacheKey.url);
      clientResponse.headers.set('X-Cache-TTL', ttl.toString());
      
      return clientResponse;
    }
  }
  
  const finalResponse = new Response(response.body, response);
  finalResponse.headers.set('X-Cache', 'BYPASS');
  return finalResponse;
}